from __future__ import annotations

from typing import List

from query_lexer import LexError, Token, tokenize

from .errors import ParseError
from .nodes import And, Call, Comparison, Not, Or

_VALUE_TYPES = ("STRING", "NUMBER", "DATE", "BOOLEAN")
_ARGUMENT_TYPES = ("IDENT",) + _VALUE_TYPES


class _Parser:
    def __init__(self, tokens: List[Token]) -> None:
        self._tokens = tokens
        self._pos = 0

    def _peek(self) -> Token:
        return self._tokens[self._pos]

    def _peek_next(self) -> Token:
        if self._pos + 1 < len(self._tokens):
            return self._tokens[self._pos + 1]
        return self._tokens[-1]

    def _advance(self) -> Token:
        token = self._tokens[self._pos]
        if token.type != "EOF":
            self._pos += 1
        return token

    def _expect(self, token_type: str) -> Token:
        token = self._peek()
        if token.type != token_type:
            raise ParseError(
                f"expected {token_type} but found {token.type} ({token.value!r})"
            )
        return self._advance()

    def finished(self) -> bool:
        return self._peek().type == "EOF"

    def current(self) -> Token:
        return self._peek()

    def parse_expression(self):
        return self._parse_or()

    def _parse_or(self):
        left = self._parse_and()
        while self._peek().type == "OR":
            self._advance()
            right = self._parse_and()
            left = Or(left, right)
        return left

    def _parse_and(self):
        left = self._parse_not()
        while self._peek().type == "AND":
            self._advance()
            right = self._parse_not()
            left = And(left, right)
        return left

    def _parse_not(self):
        if self._peek().type == "NOT":
            self._advance()
            operand = self._parse_not()
            return Not(operand)
        return self._parse_primary()

    def _parse_primary(self):
        token = self._peek()
        if token.type == "LPAREN":
            self._advance()
            expression = self.parse_expression()
            self._expect("RPAREN")
            return expression
        if token.type == "IDENT" and self._peek_next().type == "LPAREN":
            name_token = self._advance()
            return self._parse_call(name_token)
        return self._parse_comparison()

    def _parse_call(self, name_token: Token):
        self._expect("LPAREN")
        args = []
        if self._peek().type != "RPAREN":
            args.append(self._parse_call_argument())
            while self._peek().type == "COMMA":
                self._advance()
                args.append(self._parse_call_argument())
        self._expect("RPAREN")
        return Call(name_token.value, args)

    def _parse_call_argument(self):
        token = self._peek()
        if token.type in _ARGUMENT_TYPES:
            self._advance()
            return token.value
        raise ParseError(
            f"expected an argument but found {token.type} ({token.value!r})"
        )

    def _parse_comparison(self):
        field_token = self._expect("IDENT")
        op_token = self._peek()
        if op_token.type != "OP":
            raise ParseError(
                f"expected a comparison operator after {field_token.value!r} "
                f"but found {op_token.type}"
            )
        self._advance()
        value_token = self._peek()
        if value_token.type not in _VALUE_TYPES:
            raise ParseError(
                f"expected a value after {op_token.value!r} but found {value_token.type}"
            )
        self._advance()
        return Comparison(field_token.value, op_token.value, value_token.value)


def parse(text: str):
    try:
        tokens = tokenize(text)
    except LexError as exc:
        raise ParseError(str(exc)) from exc

    parser = _Parser(tokens)
    expression = parser.parse_expression()

    if not parser.finished():
        raise ParseError(f"expected end of input but found {parser.current().type}")

    return expression
